// ── Animated press wrapper ──────────────────────────────────────────
function Card({ style, onPress, children }: {
  style?: object | object[];
  onPress?: () => void;
  children: React.ReactNode;
}) {
  const scale = useRef(new Animated.Value(1)).current;
  const spring = (v: number) =>
    Animated.spring(scale, { toValue: v, useNativeDriver: true, speed: 50, bounciness: 2 });
  if (!onPress) return <View style={style}>{children}</View>;
  return (
    <Pressable onPressIn={() => spring(0.97).start()} onPressOut={() => spring(1).start()} onPress={onPress}>
      <Animated.View style={[style, { transform: [{ scale }] }]}>{children}</Animated.View>
    </Pressable>
  );
}

