export default function Landing() {
  const pathname = usePathname();
  const [sessionLoading, setSessionLoading] = useState(true);
  const [hasSession, setHasSession]         = useState(false);
  const [tutorName, setTutorName]           = useState('');
  const [dogs, setDogs]                     = useState<any[]>([]);
  const [activeDogId, setActiveDogId]       = useState<string | null>(null);

  const fade  = useRef(new Animated.Value(0)).current;
  const slide = useRef(new Animated.Value(20)).current;

  const [uploadingDogId, setUploadingDogId] = useState<string | null>(null);

  const fetchProfile = async () => {
    try {
      const data = await apiClient.get<any>('/tutors/me');
      if (data) {
        setTutorName(data.firstName || data.email?.split('@')[0] || '');
        if (data.dogs?.length > 0) {
          setDogs(data.dogs);
          setActiveDogId(prev => {
            if (prev && data.dogs.some((d: any) => d.id === prev)) {
              return prev;
            }
            return data.dogs[0].id;
          });
        } else {
          setDogs([]);
          setActiveDogId(null);
        }
      }
    } catch (err) {
      console.error('Error fetching profile:', err);
    }
  };

  const handleUploadPhoto = async (dog: any) => {
    const permissionResult = await ImagePicker.requestMediaLibraryPermissionsAsync();

    if (permissionResult.granted === false) {
      Alert.alert('Erro', 'É necessária permissão de acesso à galeria.');
      return;
    }

    const pickerResult = await ImagePicker.launchImageLibraryAsync({
      mediaTypes: ['images'],
      allowsEditing: true,
      aspect: [1, 1],
      quality: 0.8,
    });

    if (pickerResult.canceled || !pickerResult.assets?.[0]) {
      return;
    }

    const tempUri = pickerResult.assets[0].uri;
    setUploadingDogId(dog.id);

    try {
      const response = await fetch(tempUri);
      const blob = await response.blob();

      let fileExt = 'jpg';
      if (tempUri.startsWith('data:')) {
        const mime = tempUri.split(';')[0].split(':')[1];
        fileExt = mime.split('/')[1] || 'jpg';
      } else {
        const parts = tempUri.split('.');
        const lastPart = parts[parts.length - 1];
        fileExt = lastPart.split('?')[0] || 'jpg';
      }

      fileExt = fileExt.toLowerCase();
      if (!['jpg', 'jpeg', 'png', 'gif', 'webp'].includes(fileExt)) {
        fileExt = 'jpg';
      }

      const fileName = `${dog.id}_${Date.now()}.${fileExt}`;
      const filePath = `avatars/${fileName}`;

      const { error } = await supabase.storage
        .from('dogs')
        .upload(filePath, blob, {
          contentType: `image/${fileExt === 'png' ? 'png' : 'jpeg'}`,
          upsert: true,
        });

      if (error) {
        throw error;
      }

      const { data: { publicUrl } } = supabase.storage
        .from('dogs')
        .getPublicUrl(filePath);

      const fullDog = await apiClient.get<any>(`/dogs/${dog.id}`);
      if (!fullDog) {
        throw new Error('Could not fetch full dog profile');
      }

      let neutered: string = 'unknown';
      if (fullDog.neutered === true || fullDog.neutered === 'yes') neutered = 'yes';
      else if (fullDog.neutered === false || fullDog.neutered === 'no') neutered = 'no';

      let ageRange: string = 'unknown';
      if (fullDog.birthdate) {
        const ageY = ageFromBirthdate(fullDog.birthdate);
        if (ageY !== null) {
          if (ageY < 1) ageRange = 'puppy';
          else if (ageY >= 1 && ageY <= 3) ageRange = '1_to_3';
          else if (ageY >= 4 && ageY <= 7) ageRange = '4_to_7';
          else if (ageY >= 8) ageRange = 'over_8';
        }
      }

      const payload = {
        dogId: dog.id,
        name: fullDog.name,
        gender: fullDog.gender || null,
        birthdate: fullDog.birthdate || null,
        weightKg: fullDog.weightKg || null,
        size: fullDog.size || null,
        breed: fullDog.breed || null,
        breedOther: fullDog.breedOther || null,
        ageRange: ageRange,
        neutered: neutered,
        adopted: fullDog.adopted,
        photoUrl: publicUrl,
        habitsJson: fullDog.habitsJson,
        behaviorJson: fullDog.behaviorJson,
        healthJson: fullDog.healthJson,
      };

      await apiClient.put(`/dogs/${dog.id}`, payload);

      Alert.alert('Sucesso', 'Foto atualizada com sucesso!');
      await fetchProfile();
    } catch (err) {
      console.error('Error uploading dog photo from landing:', err);
      Alert.alert('Erro', 'Não foi possível guardar a foto.');
    } finally {
      setUploadingDogId(null);
    }
  };

  useEffect(() => {
    Animated.parallel([
      Animated.timing(fade,  { toValue: 1, duration: 500, useNativeDriver: true }),
      Animated.timing(slide, { toValue: 0, duration: 500, useNativeDriver: true }),
    ]).start();

    supabase.auth.getSession().then(async ({ data: { session } }) => {
      if (session) {
        const pending = await AsyncStorage.getItem('buddyid_pending_dogs');
        if (pending && pending !== '[]') {
          router.replace('/buddyid/loading' as any);
          return;
        }

        setHasSession(true);
        fetchProfile().finally(() => setSessionLoading(false));
      } else {
        setHasSession(false);
        setSessionLoading(false);
      }
    });
  }, []);

  const activeDog = dogs.find(d => d.id === activeDogId) || dogs[0];
  const animStyle = { opacity: fade, transform: [{ translateY: slide }] };

  return (
    <SafeAreaView style={s.safe} edges={['top']}>
      {/* Header */}
      <View style={s.header}>
        <Logo variant="dark" size="md" />
        <Text style={s.headerTagline}>Dá ao teu melhor amigo a vida que ele merece</Text>
      </View>

      <ScrollView style={s.scroll} contentContainerStyle={s.content} showsVerticalScrollIndicator={false}>
        <Animated.View style={animStyle}>

          {sessionLoading ? (
            <View style={s.loadingWrap}>
              <ActivityIndicator size="large" color={colors.primary} />
            </View>

          ) : hasSession ? (
            // ── Dashboard ──
            <View style={s.dashboard}>
              <View style={s.dashHeader}>
                <View>
                  <Text style={s.welcome}>Olá, {tutorName}</Text>
                  <Text style={s.dashTitle}>O teu BuddyID</Text>
                </View>
                <TouchableOpacity onPress={async () => {
                  await supabase.auth.signOut();
                  setHasSession(false);
                  setDogs([]);
                  setTutorName('');
                }}>
                  <Text style={s.logoutText}>Terminar Sessão</Text>
                </TouchableOpacity>
              </View>

              {dogs.length > 1 && (
                <ScrollView horizontal showsHorizontalScrollIndicator={false} style={s.switcher} contentContainerStyle={s.switcherContent}>
                  {dogs.map((d) => {
                    const active = d.id === activeDogId;
                    return (
                      <TouchableOpacity key={d.id} onPress={() => setActiveDogId(d.id)} style={s.switcherItem}>
                        <View style={[s.switcherRing, active && s.switcherRingActive]}>
                          {d.photoUrl
                            ? <Image source={{ uri: d.photoUrl }} style={s.switcherAvatar} />
                            : <View style={[s.switcherAvatar, s.avatarFallback]}><Text style={s.avatarLetter}>{d.name[0].toUpperCase()}</Text></View>
                          }
                        </View>
                        <Text style={[s.switcherName, active && s.switcherNameActive]} numberOfLines={1}>{d.name}</Text>
                      </TouchableOpacity>
                    );
                  })}
                </ScrollView>
              )}

              {dogs.length === 0 && (
                <View style={{ marginBottom: spacing[4] }}>
                  <Text style={{ fontFamily: font.regular, fontSize: fontSize.base, color: colors.textSecondary }}>
                    Ainda não tens nenhum cão registado.
                  </Text>
                </View>
              )}

              {activeDog && (
                <Card style={[s.dogCard, { padding: 0, overflow: 'hidden' }]}>
                  <View style={{ position: 'relative' }}>
                    <TouchableOpacity 
                      activeOpacity={0.85} 
                      onPress={() => handleUploadPhoto(activeDog)}
                      disabled={uploadingDogId === activeDog.id}
                    >
                      {activeDog.photoUrl
                        ? <Image source={{ uri: activeDog.photoUrl }} style={s.dogPhoto} resizeMode="cover" />
                        : <View style={[s.dogPhoto, s.dogPhotoFallback]}><Text style={s.dogPhotoLetter}>{activeDog.name[0].toUpperCase()}</Text></View>
                      }
                      {uploadingDogId === activeDog.id ? (
                        <View style={s.photoLoader}>
                          <ActivityIndicator size="small" color={colors.primary} />
                        </View>
                      ) : (
                        <View style={[
                          s.photoUploadBtn,
                          activeDog.photoUrl ? s.photoUploadBtnWithPhoto : s.photoUploadBtnNoPhoto
                        ]}>
                          <CameraIcon size={16} color={activeDog.photoUrl ? colors.primary : '#fff'} />
                          {!activeDog.photoUrl && <Text style={s.photoUploadText}>Adicionar foto</Text>}
                        </View>
                      )}
                    </TouchableOpacity>
                  </View>

                  <TouchableOpacity activeOpacity={0.7} onPress={() => router.navigate(`/buddyid/dog/${activeDog.id}` as any)}>
                    <View style={s.dogInfo}>
                      <Text style={s.dogName}>{activeDog.name}</Text>
                      <Text style={s.dogMeta}>{[activeDog.breed, activeDog.gender === 'male' ? 'Macho' : 'Fêmea'].filter(Boolean).join(' · ')}</Text>
                    </View>
                  </TouchableOpacity>
                  
                  <TouchableOpacity style={[s.dogCta, { paddingHorizontal: spacing[4], paddingBottom: spacing[4], paddingTop: 0, marginTop: 0 }]} activeOpacity={0.7} onPress={() => router.navigate(`/buddyid/dog/${activeDog.id}` as any)}>
                    <Text style={s.dogCtaText}>Abrir BuddyID</Text>
                    <ChevronRightIcon size={14} color={colors.primary} />
                  </TouchableOpacity>
                </Card>
              )}

              <Card style={s.addDogCard} onPress={() => router.navigate('/buddyid/flow' as any)}>
                <Text style={s.addDogText}>Adicionar cão</Text>
                <ChevronRightIcon size={16} color={colors.primary} />
              </Card>
            </View>

          ) : (
            <>

              {/* ── Hero Card ── */}
              <Card style={s.hero} onPress={() => router.navigate('/buddyid/flow' as any)}>
                <View style={s.heroGlow} />
                <View style={s.heroDogWrap} pointerEvents="none">
                  <SvgXml xml={PETS_09_SVG} width={113} height={161} />
                </View>
                <View style={s.pill}><Text style={s.pillText}>First Pack</Text></View>
                <Text style={s.heroTitle}>
                  Cria o <Text style={s.heroTitleBold}>BuddyID</Text>{'\n'}do teu cão
                </Text>
                <Text style={s.heroSub}>
                  O passaporte digital do teu cão. Serviços, saúde e histórico num só lugar.
                </Text>
                <View style={s.heroStrip}>
                  <Text style={s.heroStripText}>
                    Por cada cão registado doamos <Text style={s.heroStripBold}>1€</Text> no primeiro serviço
                  </Text>
                </View>
                <View style={s.heroCta}>
                  <Text style={s.heroCtaText}>Começar agora</Text>
                </View>
                <TouchableOpacity onPress={() => router.navigate('/buddyid/auth?mode=login_only' as any)} style={s.heroGhost}>
                  <Text style={s.heroGhostText}>Já tens conta? Iniciar sessão</Text>
                </TouchableOpacity>
              </Card>

              {/* ── Serviços ── */}
              <Text style={s.sectionTitle}>Serviços na tua zona</Text>
              <ScrollView
                horizontal
                showsHorizontalScrollIndicator={false}
                contentContainerStyle={s.servicesCarousel}
                style={s.servicesCarouselWrap}
              >
                {SERVICES.map(({ label, Icon }) => (
                  <View key={label} style={s.serviceRect}>
                    <View style={s.serviceIconWrap}><Icon size={18} color={colors.primary} /></View>
                    <Text style={s.serviceLabel}>{label}</Text>
                  </View>
                ))}
                <View style={[s.serviceRect, s.serviceRectMore]}>
                  <Text style={s.serviceMoreText}>e mais</Text>
                </View>
              </ScrollView>

              {/* ── Como funciona o BuddyID ── */}
              <Text style={s.sectionTitle}>Como funciona o BuddyID</Text>
              <View style={s.howWrap}>
                {HOW.map((item) => (
                  <View key={item.title} style={[s.howCard, { minHeight: item.minh }]}>
                    <View style={s.howIllustration} pointerEvents="none">
                      <SvgXml xml={item.svg} width={item.iw} height={item.ih} />
                    </View>
                    <Text style={s.howCardTitle}>{item.title}</Text>
                    <Text style={s.howCardSub}>{item.sub}</Text>
                    {item.badge && (
                      <View style={s.howBadge}><Text style={s.howBadgeText}>{item.badge}</Text></View>
                    )}
                  </View>
                ))}
              </View>

              {/* ── Buddy Fund Card ── */}
              <Card style={s.fund} onPress={() => router.navigate('/buddyid/buddy-fund' as any)}>
                <View style={s.fundIllustration} pointerEvents="none">
                  <SvgXml xml={SERVICES_09_SVG} width={320} height={124} />
                </View>
                <Text style={s.fundLabel}>Buddy Fund</Text>
                <Text style={s.fundTitle}>Um cão com família{'\n'}ajuda um que ainda não tem</Text>
                <Text style={s.fundSub}>Por cada serviço, apoiamos um cão à espera de uma família.</Text>
                <View style={s.fundAction}>
                  <Text style={s.fundActionText}>Saber mais</Text>
                  <ChevronRightIcon size={16} color="#fff" strokeWidth={2} />
                </View>
              </Card>

              {/* ── Providers CTA ── */}
              <Card style={s.providerCard} onPress={() => router.navigate('/buddyid/providers' as any)}>
                <View style={[s.pill, { backgroundColor: colors.cardLilac }]}>
                  <Text style={[s.pillText, { color: '#fff' }]}>Para prestadores</Text>
                </View>
                <Text style={s.providerTitle}>Faz parte dos primeiros prestadores da Buddy</Text>
                <Text style={s.providerSub}>0% de comissão nos primeiros 6 meses para quem entra no pré-lançamento.</Text>
                <View style={[s.fundAction, { backgroundColor: colors.cardLilac }]}>
                  <Text style={s.fundActionText}>Saber mais</Text>
                  <ChevronRightIcon size={16} color="#fff" strokeWidth={2} />
                </View>
              </Card>
            </>
          )}
        </Animated.View>
      </ScrollView>

      <NavBar />
    </SafeAreaView>
  );
}

